Class License Extends %RegisteredObject
{
    Property ExpirationDate As %Date;

    /// Check if license is expired
    Method IsExpired() As %Boolean
    {
        Set today = +$HOROLOG
        // BUGGY: Wrong comparison operator - should check if expiration is BEFORE today
        Quit ..ExpirationDate > today
    }
}

