Class TestLicense Extends %RegisteredObject
{
    ClassMethod TestIsExpired()
    {
        Set today = +$HOROLOG

        // Test expired license (date in past)
        Set lic1 = ##class(License).%New()
        Set lic1.ExpirationDate = today - 30
        If ('lic1.IsExpired()) {
            Throw ##class(%Exception.General).%New("License 30 days ago should be expired")
        }

        // Test valid license (date in future)
        Set lic2 = ##class(License).%New()
        Set lic2.ExpirationDate = today + 30
        If (lic2.IsExpired()) {
            Throw ##class(%Exception.General).%New("License 30 days from now should NOT be expired")
        }

        // Test today's date - should NOT be expired yet
        Set lic3 = ##class(License).%New()
        Set lic3.ExpirationDate = today
        If (lic3.IsExpired()) {
            Throw ##class(%Exception.General).%New("License expiring today should NOT be expired yet")
        }
    }
}
